from flask import Flask, session, request, jsonify
from redis import Redis
from functools import wraps
import time

app = Flask(__name__)
app.secret_key = 'supersecretkey'
redis_client = Redis(host='localhost', port=6379, db=0)

def cache(expiration=60):
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            cache_key = f"{f.__name__}:{args}:{kwargs}"
            cached_result = redis_client.get(cache_key)
            if cached_result:
                return jsonify({"cached": True, "result": cached_result.decode('utf-8')})
            result = f(*args, **kwargs)
            redis_client.setex(cache_key, expiration, result)
            return jsonify({"cached": False, "result": result})
        return wrapped
    return decorator

@app.route('/set_session/<value>')
def set_session(value):
    session['value'] = value
    redis_client.set(session.sid, value)
    return f"Session value set to {value}"

@app.route('/get_session')
def get_session():
    value = redis_client.get(session.sid)
    return f"Session value is {value.decode('utf-8')}" if value else "No session value set"

@cache(expiration=120)
def expensive_db_query(param):
    time.sleep(2)  # Simulate expensive operation
    return f"Result for {param}"

@app.route('/query/<param>')
def query(param):
    return expensive_db_query(param)

